#include<bits/stdc++.h>
using namespace std;
long long f[3000010],c[3000010],a[3000010],d[3000010],r,lst[3000010];
bool b[3000010];
char s[3000010];
int main()
{
    long long n;
    scanf("%lld%s",&n,s+1);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=(s[i]=='(');
    }
    for(long long i=1;i<=n;i++)
    {
        if(!b[i]&&r)
        {
            lst[i]=d[r--];
        }
        else if(b[i])
        {
            d[++r]=i;
        }
    }
    memset(f,-0x3f,sizeof(f));
    memset(c,-0x3f,sizeof(c));
    f[0]=0;
    for(long long i=1;i<=n;i++)
    {
        f[i]=f[i-1];
        if(lst[i]!=0)
        {
            c[i]=max(c[lst[i]-1],f[lst[i]-1]-a[lst[i]]);
            f[i]=max(f[i],c[i]+a[i]);
        }
    }
    printf("%lld",f[n]);
    return 0;
}
